Extract approval details.

Format:
{
  "tasks": [{
    "action": "update",
    "taskReference": "Task ID from message",
    "description": "Approval note",
    "billable": true/false,
    "tags": ["approved"],
    "moveToColumn": "To Do"
  }]
}

IMPORTANT: Respond ONLY with valid JSON.

Extract testing completion details.

Format:
{
  "tasks": [{
    "action": "update",
    "taskReference": "Task ID",
    "testingComplete": true,
    "tags": ["tested"],
    "moveToColumn": "Tested",
    "readyForClient": true
  }]
}

IMPORTANT: Respond ONLY with valid JSON.

parameters.jsCode:
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    let content = '';
    if (item.json.choices && item.json.choices[0]) {
      content = item.json.choices[0].message.content;
    } else if (item.json.content) {
      content = item.json.content;
    } else {
      throw new Error('No AI response');
    }

    content = content.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
    const parsed = JSON.parse(content);

    const emailData = item.json;
    const hasTaskArray = parsed.tasks && Array.isArray(parsed.tasks);

    if (hasTaskArray) {
      parsed.tasks.forEach((task, idx) => {
        results.push({
          json: {
            taskId: `task-${Date.now()}-${idx}`,
            subject: task.subject || emailData.subject,
            description: task.description || '',
            board: task.board || emailData.defaultBoard || 'Backlog',
            column: task.column || task.moveToColumn || emailData.defaultColumn || 'Backlog',
            tags: task.tags ? task.tags.join(',') : emailData.defaultTags || '',
            priority: emailData.priority || 'medium',
            action: task.action || 'create',
            estimatedHours: task.estimatedHours || null,
            storyPoints: task.storyPoints || null,

            // Completeness check
            complete: parsed.complete !== false,
            missingInfo: parsed.missingInfo || [],
            attachmentsNeeded: task.attachmentsNeeded || [],

            // Workflow control
            messageType: emailData.messageType || 'unknown',
            workflowPhase: emailData.workflowPhase || 'collect',
            billable: task.billable || false,
            needsManagerApproval: task.needsManagerApproval || false,
            testingComplete: task.testingComplete || false,
            readyForClient: task.readyForClient || false,
            taskReference: task.taskReference || null,

            // Metadata
            emailFrom: emailData.from,
            emailDate: emailData.date,
            emailSubject: emailData.subject,
            createdAt: new Date().toISOString(),
            status: 'todo',
            parseSuccess: true
          }
        });
      });
    } else {
      throw new Error('Invalid structure: tasks array required');
    }
  } catch (error) {
    results.push({
      json: {
        taskId: `error-${Date.now()}`,
        subject: item.json.subject || 'Parse Error',
        parseSuccess: false,
        parseError: error.message,
        rawContent: JSON.stringify(item.json)
      }
    });
  }
}

return results;

