// Calculate client cost based on estimated hours and rate
const items = $input.all();
const results = [];

for (const item of items) {
  const estimatedHours = item.json['Estimated Hours'] || item.json.estimatedHours || 0;
  const hourlyRate = 75; // EUR per hour
  const coefficient = 1.2; // 20% margin

  const clientCost = Math.round(estimatedHours * hourlyRate * coefficient);

  results.push({
    json: {
      ...item.json,
      clientCost: clientCost,
      currency: 'EUR',
      hourlyRate: hourlyRate,
      coefficient: coefficient
    }
  });
}

return results;

