// Compile billing report
const items = $input.all();
const tasks = items.map(item => item.json);

const report = {
  period: new Date().toISOString().slice(0, 7),
  totalTasks: tasks.length,
  totalHours: tasks.reduce((sum, t) => sum + (t['Estimated Hours'] || 0), 0),
  totalCost: tasks.reduce((sum, t) => {
    const hours = t['Estimated Hours'] || 0;
    return sum + (hours * 75 * 1.2);
  }, 0),
  tasksByType: {
    feature: tasks.filter(t => t.Tags && t.Tags.includes('feature')).length,
    bug: tasks.filter(t => t.Tags && t.Tags.includes('bug')).length,
    other: tasks.filter(t => !t.Tags || (!t.Tags.includes('feature') && !t.Tags.includes('bug'))).length
  },
  tasks: tasks.map(t => ({
    id: t['Task ID'],
    subject: t.Subject,
    hours: t['Estimated Hours'],
    cost: Math.round((t['Estimated Hours'] || 0) * 75 * 1.2),
    status: t.Status,
    column: t.Column
  }))
};

return [{ json: report }];

